PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "dokters" ("id_dokter" integer primary key autoincrement not null, "user_id" integer not null, "nama_dokter" varchar, "role" varchar, "nip" varchar, "alamat" varchar, "tanggal_lahir" date, "nik" varchar, "nohp" varchar, "jadwalpraktik" varchar, "penghasilan" numeric not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "admins" ("id" integer primary key autoincrement not null, "user_id" integer not null, "nama_admin" varchar not null, "role" varchar not null, "nip" varchar not null, "alamat" varchar not null, "tanggal_lahir" date not null, "nik" varchar not null, "nohp" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "manajers" ("id" integer primary key autoincrement not null, "user_id" integer not null, "nama_manajer" varchar not null, "role" varchar not null, "nip" varchar not null, "alamat" varchar not null, "tanggal_lahir" date not null, "nik" varchar not null, "nohp" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "obats" ("id_obat" integer primary key autoincrement not null, "nama_obat" varchar not null, "merk" varchar not null, "ukuran" varchar not null, "harga_beli" numeric not null, "tanggal_beli" date not null, "supplier" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "pasiens" ("id_pasien" integer primary key autoincrement not null, "nama_pasien" varchar not null, "jenis_kelamin" varchar check ("jenis_kelamin" in ('L', 'P')) not null, "alamat_pasien" varchar not null, "profesi" varchar, "nik" varchar not null, "nohp" varchar not null, "alergi" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "kasirs" ("id" integer primary key autoincrement not null, "tindakan_id" integer not null, "total_biaya" numeric not null, "dibayar" numeric not null default '0', "kembalian" numeric not null default '0', "metode_pembayaran" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("tindakan_id") references "tindakans"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "laporan_keuangans" ("id" integer primary key autoincrement not null, "kasir_id" integer not null, "total_transaksi" numeric not null, "tanggal" date not null, "created_at" datetime, "updated_at" datetime, foreign key("kasir_id") references "kasirs"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "tindakans" ("id" integer primary key autoincrement not null, "dokter_id" integer not null, "pasien_id" integer not null, "tanggal_visit" date not null, "jam" time not null, "tindakan" varchar not null, "pemakaian_obat" text, "tindak_lanjut" text, "created_at" datetime, "updated_at" datetime, foreign key("dokter_id") references "dokters"("id_dokter") on delete cascade, foreign key("pasien_id") references "pasiens"("id_pasien") on delete cascade);
CREATE TABLE IF NOT EXISTS "kasuses" ("id" integer primary key autoincrement not null, "tindakan_id" integer not null, "kasus" varchar not null, "diagnosa" varchar not null, "tindakan_khusus" varchar not null, "biaya" numeric not null, "created_at" datetime, "updated_at" datetime, foreign key("tindakan_id") references "tindakans"("id") on delete cascade);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
COMMIT;
